SELECT ASMT.ASMT_ID , ASMT.SBJCT_ID , OFRNG.SBJCTNM , ( SELECT DGRS_SMSTR_CHRT FROM TB_LMS_SMSTR_CHRT T WHERE T.SMSTR_CHRT_ID = OFRNG.SMSTR_CHRT_ID) AS DGRS_SMSTR_CHRT , ASMT.ASMT_GBNCD , ( SELECT CDNM FROM TB_LMS_CMMN_CD WHERE UP_CD = 'ASMT_GBNCD' AND CD = ASMT.ASMT_GBNCD AND ORG_ID = #{orgId} AND LANG_CD = NVL(#{langCd}, 'ko') ) AS ASMT_GBNNM , ASMT.ASMT_TTL , ASMT.ASMT_CTS , ASMT.ASMT_SBMSN_SDTTM , ASMT.ASMT_SBMSN_EDTTM , ASMT.ASMT_PRCTCYN , ASMT.SBASMT_TYCD , ASMT.SBMSN_FILE_MIME_TYCD , ASMT.ASMT_OYN , ASMT.EXTD_SBMSN_PRMYN , ASMT.EXTD_SBMSN_SDTTM , ASMT.EXTD_SBMSN_EDTTM , ASMT.TEAM_ASMT_STNGYN , ASMT.LRN_GRP_ID , ( SELECT LRN_GRPNM FROM TB_LMS_TEAM_GRP WHERE LRN_GRP_ID = ASMT.LRN_GRP_ID AND USEYN = 'Y' AND ASMT.DELYN = 'N') AS LRN_GRPNM , ASMT.TMBR_SBMSN_PRMYN , ASMT.MRK_RFLTYN , ASMT.MRK_RFLTRT , ASMT.MRK_OYN , ASMT.MRK_INQ_SDTTM , ASMT.MRK_INQ_EDTTM , ASMT.EVL_SCR_TYCD , ASMT.EVL_RSLT_OYN , ASMT.AVG_SCR_OYN , ASMT.PUSH_ALIMYN , ASMT.SBASMT_OSTD_OYN , ASMT.SBASMT_OSTD_OPEN_SDTTM , ASMT.SBASMT_OSTD_OPEN_EDTTM , ASMT.INDV_ASMTYN , ASMT.RESBMSN_SDTTM , ASMT.RESBMSN_EDTTM , ASMT.RESBMSN_MRK_RFLTRT , ASMT.LCTR_WKNO_SCHDL_ID
, ASMT.DELYN , ASMT.RGTR_ID , ( SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = ASMT.RGTR_ID) AS RGTRNM , ASMT.REG_DTTM , ASMT.MDFR_ID , ( SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = ASMT.MDFR_ID) AS MDFRNM , ASMT.MOD_DTTM
-- , NVL((SELECT 'Y' FROM TB_LMS_EXAM_BSC T1 JOIN TB_LMS_EXAM_EVL_SBST T2 ON T2.EXAM_BSC_ID = T1.EXAM_BSC_ID WHERE T1.EXAM_SBST_REF_ID = ASMT.ASMT_ID AND T1.EXAM_TYCD = 'EXAM' AND T1.DELYN = 'N'), 'N') AS examInsYn -- , NVL((SELECT TKEXAM_MTHD_CD FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = ASMT.ASMT_ID AND EXAM_TYCD = 'EXAM' AND DELYN = 'N'), '') AS examStareTypeCd -- , NVL((SELECT EXAM_BSC_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = ASMT.ASMT_ID AND EXAM_TYCD = 'EXAM' AND DELYN = 'N'), '') AS parExamBscId -- , NVL((SELECT EXAM_PSBL_EYMD FROM TB_LMS_EXAM_BSC T1 JOIN TB_LMS_EXAM_DTL T2 ON T2.EXAM_BSC_ID = T1.EXAM_BSC_ID WHERE T1.EXAM_SBST_REF_ID = ASMT.ASMT_ID AND T1.EXAM_TYCD = 'EXAM' AND T1.DELYN = 'N'), '') AS parExamEndDttm FROM TB_LMS_ASMT ASMT JOIN TB_LMS_SBJCT OFRNG ON OFRNG.SBJCT_ID = ASMT.SBJCT_ID WHERE ASMT.DELYN = 'N'
AND OFRNG.SBJCT_ID = #{sbjctId}
AND OFRNG.SMSTR_CHRT_ID = #{smstrChrtId}
AND LOWER(ASMT.ASMT_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))

mapper.select:
		/*
             SQL ID : AsmntProDAO.selectObject
             	설  명 : 과제 정보 조회
         */	

		AND ASMT.ASMT_ID = #{asmtId}

mapper.insert:
/*
	SQL ID : AsmntProDAO.insertAsmtGrp
	설  명 : 과제그룹 등록
 */

INSERT INTO TB_LMS_ASMT_GRP
(
      ASMT_GRP_ID
    , ASMT_GRPNM
    , RGTR_ID
    , REG_DTTM
)
VALUES
(
      #{asmtGrpId}
    , #{asmtGrpId}
    , #{rgtrId}
    , FN_DTTM()
)

/* SQL ID : AsmntProDAO.copyAsmnt 설 명 : 과제 복사 */ INSERT INTO TB_LMS_ASMT ( ASMT_ID , SBJCT_ID , ASMT_CTGRCD , ASMT_TTL , ASMT_CTS , DVCLAS_REGYN , SEND_START_DTTM , SEND_END_DTTM , MRK_RFLTYN , MRK_RFLTRT , ASMNT_OPEN_YN , EXT_SEND_ACPT_YN , EXT_SEND_DTTM , EVL_CTGRCD , PRTC_YN , SEND_TYPE , SBMT_FILE_TYPE , TEAM_ASMNT_CFG_YN
, IND_YN , MRK_OYN , SBMT_OPEN_YN , SBMT_START_DTTM , SBMT_END_DTTM , EVAL_USE_YN , EVL_SDTTM , EVL_EDTTM , EVL_RSLT_OYN , DELYN , RGTR_ID , FRST_INQ_DTTM ) SELECT #{asmtId} , #{crsCreCd} , ASMT_CTGRCD , ASMT_TTL , ASMT_CTS , 'N' , SEND_START_DTTM , SEND_END_DTTM , MRK_RFLTYN , MRK_RFLTRT , ASMNT_OPEN_YN , EXT_SEND_ACPT_YN , EXT_SEND_DTTM , EVL_CTGRCD , PRTC_YN , SEND_TYPE , SBMT_FILE_TYPE , TEAM_ASMNT_CFG_YN
, IND_YN , MRK_OYN , SBMT_OPEN_YN , SBMT_START_DTTM , SBMT_END_DTTM , EVAL_USE_YN , EVL_SDTTM , EVL_EDTTM , EVL_RSLT_OYN , DELYN , #{rgtrId}
, FN_DTTM_ADD_SEC(#{lineNo})
, FN_DTTM()
FROM TB_LMS_ASMT WHERE ASMT_ID = #{copyasmntId}

mapper.update:
		/*
             SQL ID : AsmntProDAO.updateAsmnt
             	설  명 : 과제 수정
         */		
		UPDATE TB_LMS_ASMT
		  SET MDFR_ID = #{userId}
			, MOD_DTTM = FN_DTTM()

			, ASMT_TTL = #{asmtTtl}


			, ASMT_CTS = #{asmtCts}


			, ASMT_CTGRCD = #{asmtGbncd}


			, SEND_START_DTTM = TO_CHAR(CASE WHEN LENGTH(#{asmtSbmsnSdttm}) = 14 THEN TO_DATE(#{asmtSbmsnSdttm}, 'YYYYMMDDHH24MISS') ELSE TO_DATE(#{asmtSbmsnSdttm}, 'YYYY-MM-DD HH24:MI:SS') END, 'YYYYMMDDHH24MISS')


       		, SEND_END_DTTM = TO_CHAR(CASE WHEN LENGTH(#{sendEndDttm}) = 14 THEN TO_DATE(#{sendEndDttm}, 'YYYYMMDDHH24MISS') ELSE TO_DATE(#{sendEndDttm}, 'YYYY-MM-DD HH24:MI:SS') END, 'YYYYMMDDHH24MISS')


			, EXT_SEND_ACPT_YN = #{extdSbmsnPrmyn}


			, EXT_SEND_DTTM = TO_CHAR(CASE WHEN LENGTH(#{extdSbmsnSdttm}) = 14 THEN TO_DATE(#{extdSbmsnSdttm}, 'YYYYMMDDHH24MISS') ELSE TO_DATE(#{extdSbmsnSdttm}, 'YYYY-MM-DD HH24:MI:SS') END, 'YYYYMMDDHH24MISS')


			, EXT_SEND_DTTM = NULL


			, EVL_CTGRCD = #{evalCtgr}


			, MRK_RFLTYN = #{mrkRfltyn}


			, MRK_OYN = #{mrkOyn}


			, PRTC_YN = #{asmtPrctcyn}


			, SEND_TYPE = #{sendType}
			, SBMT_FILE_TYPE = #{sbmtFileType}


			, TEAM_ASMNT_CFG_YN = #{teamAsmtStngyn}


			, TEAM_TYCD = #{lrnGrpId}


			, TEAM_EVAL_YN = #{teamEvalYn}


			, IND_YN = #{indvAsmtyn}


			, MRK_RFLTRT = 0


			, SBMT_OPEN_YN = #{sbasmtOstdOyn}


			, SEND_START_DTTM = TO_CHAR(CASE WHEN LENGTH(#{sbasmtOstdOpenSdttm}) = 14 THEN TO_DATE(#{sbasmtOstdOpenSdttm}, 'YYYYMMDDHH24MISS') ELSE TO_DATE(#{sbasmtOstdOpenSdttm}, 'YYYY-MM-DD HH24:MI:SS') END, 'YYYYMMDDHH24MISS')


			, SEND_END_DTTM = TO_CHAR(CASE WHEN LENGTH(#{sbasmtOstdOpenEdttm}) = 14 THEN TO_DATE(#{sbasmtOstdOpenEdttm}, 'YYYYMMDDHH24MISS') ELSE TO_DATE(#{sbasmtOstdOpenEdttm}, 'YYYY-MM-DD HH24:MI:SS') END, 'YYYYMMDDHH24MISS')


			, EVAL_USE_YN = #{evlRfltyn}


			, EVL_SDTTM = TO_CHAR(CASE WHEN LENGTH(#{evlSdttm}) = 14 THEN TO_DATE(#{evlSdttm}, 'YYYYMMDDHH24MISS') ELSE TO_DATE(#{evlSdttm}, 'YYYY-MM-DD HH24:MI:SS') END, 'YYYYMMDDHH24MISS')


			, EVL_EDTTM = TO_CHAR(CASE WHEN LENGTH(#{evlEdttm}) = 14 THEN TO_DATE(#{evlEdttm}, 'YYYYMMDDHH24MISS') ELSE TO_DATE(#{evlEdttm}, 'YYYY-MM-DD HH24:MI:SS') END, 'YYYYMMDDHH24MISS')


			, EVL_RSLT_OYN = #{evlRsltOyn}


			, PUSH_NOTIYN = #{pushAlimyn}


			, ASMNT_OPEN_YN = #{asmtOyn}




					, LCTR_SCHDL_ID = NULL


					, LCTR_SCHDL_ID = #{lctrWknoSchdlId}



		WHERE ASMT_ID = #{asmtId}

mapper.insert:
		/*
             SQL ID : AsmntProDAO.insertAsmntCreCrsRltn
             	설  명 : 개설과정과제 연결 등록
         */
		INSERT INTO TB_LMS_ASMNT_CRE_CRS_RLTN (
			SBJCT_ID
			, ASMT_ID
			, GRPCD
			, DELYN
		) VALUES (
			#{crsCreCd}
			, #{asmtId}
			, #{grpCd}
			, 'N'
		)

mapper.update:
		/*
             SQL ID : AsmntProDAO.updateScoreOpen
             	설  명 : 성적공개여부 수정
         */		
	   UPDATE TB_LMS_ASMT
	      SET MRK_OYN = UPPER(#{mrkOyn})
	          , MDFR_ID = #{userId}
	          , MOD_DTTM = FN_DTTM()
	    WHERE ASMT_ID = #{asmtId}

		/*
             SQL ID : AsmntProDAO.updateScoreRatio
             	설  명 : 성적반영비율 수정
         */	
	   UPDATE TB_LMS_ASMT
	      SET MRK_RFLTRT = #{mrkRfltrt}
	          , MDFR_ID = #{userId}
	          , MOD_DTTM = FN_DTTM()
	    WHERE ASMT_ID = #{asmtId}

mapper.insert:
		/*
             SQL ID : AsmntProDAO.insertFdbk
             	설  명 : 피드백 등록
         */	
		INSERT TB_LMS_ASMNT_FDBK (
			  ASMT_FDBK_ID
			, ASMT_ID
			, FDBK_TRGT_CD
			, STD_ID
			, FDBK_CTS
			, DELYN
			, RGTRNM
			, RGTR_ID
			, FRST_INQ_DTTM
		) VALUES (
			  #{asmntFdbkId}
			, #{asmtId}
			, #{fdbkTrgtUnitTycd}
			, #{stdNo}
			, #{fdbkCts}
			, 'N'
			, ( SELECT USERNM
         	      FROM TB_LMS_USR
        		 WHERE USER_ID = #{userId})
			, #{userId}
			, FN_DTTM()
		)

mapper.update:
		/*
             SQL ID : AsmntProDAO.updateFdbk
             	설  명 : 피드백 수정
         */	
		UPDATE TB_LMS_ASMNT_FDBK
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , FDBK_CTS = #{fdbkCts}
		 WHERE ASMT_FDBK_ID = #{asmntFdbkId}

		/*
             SQL ID : AsmntProDAO.deleteFdbk
             	설  명 : 피드백 삭제
         */		
		UPDATE TB_LMS_ASMNT_FDBK
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , DELYN = 'Y'
		 WHERE ASMT_FDBK_ID = #{asmntFdbkId}

		/*
             SQL ID : AsmntProDAO.updateResendInfo
             	설  명 : 제재출 수정
         */		
		UPDATE TB_LMS_ASMT
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
		   	   , RESEND_START_DTTM = DATE_FORMAT(#{resbmsnSdttm}, '%Y%m%d%H%i%s')
			   , RESEND_END_DTTM = DATE_FORMAT(#{resbmsnEdttm}, '%Y%m%d%H%i%s')
			   , RESCORE_RATIO = #{resbmsnMrkRfltrt}
		 WHERE ASMT_ID = #{asmtId}

		/*
             SQL ID : AsmntProDAO.setScoreRatio
             	설  명 : 성적반영비율 초기화
         */	
		UPDATE TB_LMS_ASMT
			SET MRK_RFLTRT = #{mrkRfltrt}
		WHERE ASMT_ID = #{asmtId}

mapper.select:
/* SQL ID : AsmntProDAO. 설 명 : 이전과제 목록selectPrevAsmntList */ SELECT RT.* , ROW_NUMBER() OVER(ORDER BY RT.FRST_INQ_DTTM) AS LINE_NO , COUNT(RT.ASMT_ID) OVER() AS TOTAL_CNT FROM (SELECT A.ASMT_ID , ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE CRS_SMSTR_ID = B.CRS_SMSTR_ID) AS DGRS_SMSTR , ( SELECT CDNM FROM TB_ORG_CODE WHERE CTGRCD = 'ASMT_CTGRCD' AND CD = A.ASMT_CTGRCD AND ORG_ID = #{orgId}) AS ASMNT_CTGR_NM , A.ASMT_TTL , A.FRST_INQ_DTTM , C.SBJCTNM , C.DVCLAS_NO FROM TB_LMS_ASMT A , TB_LMS_TERM_CRE_CRS_RLTN B , TB_LMS_SBJCT C WHERE A.DELYN = 'N' AND A.SBJCT_ID = B.SBJCT_ID AND B.SBJCT_ID = C.SBJCT_ID AND C.DELYN = 'N' AND A.SBJCT_ID IN (SELECT SBJCT_ID FROM SBJCT_PROF WHERE USER_ID = #{userId} AND PROF_TYCD != 'MONITORING')
AND A.SBJCT_ID = #{crsCreCd}
AND C.SBJCT_ID = #{creYear}
AND C.CRS_ID = #{creTerm}
AND ( LOWER(A.ASMT_CTGRCD) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.ASMT_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) ) COLLATE utf8mb4_general_ci
) RT ORDER BY RT.FRST_INQ_DTTM DESC LIMIT #{firstIndex}, #{listScale}

mapper.insert:
		/*
             SQL ID : AsmntProDAO.insertMutEvalRslt
             	설  명 : 루브릭 평가 연결 등록
         */
         INSERT INTO TB_LMS_ASMT_MTL_EVL_RSLT (
              MTL_EVL_CD
			, ASMT_MTL_EVL_RSLT_ID
			, LINK_CD
			, STD_ID
			, EVL_DTTM
			, QSTN_ID
			, GRDCD
			, EVL_SCR
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		) VALUES (
			  #{mutEvalCd}
			, #{asmtEvlId}
			, #{rltnCd}
			, #{stdNo}
			, FN_DTTM()
			, #{qstnCd}
			, #{gradeCd}
			, IFNULL(#{evalScore}, 0)
			, #{rgtrId}
			, FN_DTTM()
			, #{mdfrId}
			, FN_DTTM()
        )

mapper.update:
		/*
             SQL ID : AsmntProDAO.updateMutEvalRslt
             	설  명 : 루브릭 평가 연결 수정
         */
         UPDATE TB_LMS_ASMT_MTL_EVL_RSLT SET
         	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, EVL_DTTM = FN_DTTM()
         	, GRDCD = #{gradeCd}
         	, EVL_SCR = IFNULL(#{evalScore}, 0)
          WHERE ASMT_MTL_EVL_RSLT_ID = #{asmtEvlId}
            AND LINK_CD = #{rltnCd}
            AND STD_ID = #{stdNo}
            AND QSTN_ID = #{qstnCd}

mapper.delete:
		/*
             SQL ID : AsmntProDAO.deleteMutEvalRslt
             	설  명 : 루브릭 평가 연결 삭제
         */
         DELETE FROM TB_LMS_ASMT_MTL_EVL_RSLT
          WHERE LINK_CD = #{rltnCd}

		/*
             SQL ID : AsmntProDAO.deleteMutEvalRsltByStdNo
             	설  명 : 과제 대상자 루브릭 평가 연결 삭제
         */
         DELETE FROM TB_LMS_ASMT_MTL_EVL_RSLT
          WHERE LINK_CD = #{asmtId}
            AND STD_ID = #{stdNo}
